-- Raw uploaded 15Five export rows (statement level) for the 2025 H1 period, so
-- the Raw Responses tab can show the source data behind the import. Department-
-- level (from the 'engagement statements' export) + company-level (drivers /
-- manager effectiveness / organizational commitment). Idempotent.
CREATE TABLE IF NOT EXISTS "engagement_import_rows" (
  "id" uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  "period_id" uuid NOT NULL REFERENCES "survey_periods"("id") ON DELETE CASCADE,
  "scope" varchar(16) NOT NULL,
  "group_name" varchar(120),
  "dimension" varchar(80),
  "statement" text NOT NULL,
  "avg_response" numeric(4,2),
  "unfavorable" integer, "neutral" integer, "favorable" integer, "no_response" integer,
  "total_responses" integer, "total_possible" integer, "response_rate" numeric(5,2)
);
--> statement-breakpoint
ON CONFLICT ("id") DO NOTHING;
